import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"童年游戏节选","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/童年游戏节选.md","filePath":"4.资源分区/6.技艺及称号/杂项/童年游戏节选.md"}'),d={name:"4.资源分区/6.技艺及称号/杂项/童年游戏节选.md"};function p(_,a,l,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"童年游戏节选",tabindex:"-1"},[s("童年游戏节选 "),e("a",{class:"header-anchor",href:"#童年游戏节选","aria-label":'Permalink to "童年游戏节选"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌032")])])],-1),o('<h1 id="童年游戏节选-1" tabindex="-1">童年游戏节选 <a class="header-anchor" href="#童年游戏节选-1" aria-label="Permalink to &quot;童年游戏节选&quot;">​</a></h1><p>童年游戏节选<br> 仅致以美好的童年。<br> 在那个电子设施并不先进的年代，娱乐并不匮乏。</p><p>跳房子250<br> 玩家需单脚或双脚交替跳跃通过数字标记的格子，同时踢动沙包或石块，过程中不得踩线或双脚落地，最终以完成所有格子或占据最多“房子”为胜。<br> 你在【运动】下开启专业【跳房子】，并提升为1级</p><p>跳房子D+500<br> 房子当然是【房子】，跳房子当然也可以是【跳房子】<br> 你现在可以使用【跳房子】专业来代替【跳跃】专业来进行检定。<br> 你现在可以在垂直平面上进行移动，但若回合结束时没有落脚点会正常坠落。</p><p>滚铁圈1000<br> 在使用此技艺的时候你会自动获得一个前段为U形的铁丝和一个圆铁环。<br> 使用者进行一个持续十分钟的加速准备行为，在这期间不可中断准备行为，在准备完成后即可以旅行速度进行旅行。进行旅行时你需要以铁丝来推着铁环行动，同时在旅行前进行一个【平衡】检定，你可以在一小时内旅行成功数×5公里的距离，上限为200公里每小时，这是一个D级旅行效果。</p><p>丢沙包750<br> 你现在获得了一个武器伤害为0B的沙包，现在你可以花费标准动作以投掷攻击检定丢出沙包来进行一次命中检定，这次不造成伤害，若是命中，则对方获得1点别的可豁免的沮丧点数，这是无支线心灵来源。沙包可以在使用此技艺时取出。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
